                        HStack {
                            Image(systemName: theme.icon)
                            Text(theme.localizationKey.localized)
                            if selected == theme {
                                Image(systemName: "checkmark")
                            }
                        }
                    }
                }
            } label: {
                HStack(spacing: 4) {
                    Text(selected.localizationKey.localized)
                        .font(.system(size: 14))
                        .foregroundStyle(FitTodayColor.textSecondary)
                    Image(systemName: "chevron.up.chevron.down")
                        .font(.system(size: 10))
                        .foregroundStyle(FitTodayColor.textTertiary)
                }
            }
        }
        .padding(.horizontal, FitTodaySpacing.md)
        .padding(.vertical, FitTodaySpacing.sm)
    }

    // MARK: - Language Row

    @MainActor
    private var languageRow: some View {
        let manager = LocalizationManager.shared
        return HStack(spacing: FitTodaySpacing.md) {
            ZStack {
                RoundedRectangle(cornerRadius: 8)
                    .fill(FitTodayColor.brandPrimary.opacity(0.15))
                    .frame(width: 36, height: 36)
                Image(systemName: "globe")
                    .font(.system(size: 16))
                    .foregroundStyle(FitTodayColor.brandPrimary)
            }

            Text("settings.language".localized)
                .font(.system(.body))
                .foregroundStyle(FitTodayColor.textPrimary)

            Spacer()

            Menu {
                ForEach(LocalizationManager.Language.allCases) { language in
                    Button {
                        manager.setLanguage(language)
                    } label: {
                        HStack {
                            Text(language.displayName)
                            if manager.selectedLanguage == language {
                                Image(systemName: "checkmark")
                            }
                        }
                    }
                }
            } label: {
                HStack(spacing: 4) {
                    Text(manager.selectedLanguage.displayName)
                        .font(.system(size: 14))
                        .foregroundStyle(FitTodayColor.textSecondary)
                    Image(systemName: "chevron.up.chevron.down")
                        .font(.system(size: 10))
                        .foregroundStyle(FitTodayColor.textTertiary)
                }
            }
        }
        .padding(.horizontal, FitTodaySpacing.md)
        .padding(.vertical, FitTodaySpacing.sm)
    }

    // MARK: - Account Section

    private var accountSection: some View {
        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
            Text("settings.account".localized)
                .font(.system(size: 13, weight: .semibold))
                .foregroundStyle(FitTodayColor.textSecondary)
                .padding(.leading, 4)

            VStack(spacing: 0) {
                SettingsRow(icon: "arrow.counterclockwise", title: "settings.restore_purchases".localized) {
                    Task { await restorePurchases() }
                }

                Divider().padding(.leading, 56)

                SettingsRow(icon: "questionmark.circle", title: "settings.help_support".localized) {
                    openSupportURL()
                }

            }
            .background(FitTodayColor.surface)
            .clipShape(RoundedRectangle(cornerRadius: 16))
        }
    }

    // MARK: - Paywall Sheet

    @ViewBuilder
    private var paywallSheet: some View {
        OptimizedPaywallView(
            onPurchaseSuccess: {
                Task { await loadEntitlement() }
            },
            onDismiss: {}
        )
    }

    // MARK: - Actions

    private func loadProfileData() async {
        // Load user name
        if let cachedName = UserDefaults.standard.string(forKey: "socialUserDisplayName"), !cachedName.isEmpty {
            userName = cachedName
        }

        // Load workout history stats
        if let historyRepo = resolver.resolve(WorkoutHistoryRepository.self) {
            do {
                let entries = try await historyRepo.listEntries()
                completedWorkouts = entries.count
                totalMinutes = entries.reduce(0) { $0 + ($1.durationMinutes ?? 0) }

                // Calculate streak
                let calendar = Calendar.current
                let today = calendar.startOfDay(for: Date())
                let sortedDates = entries.map { calendar.startOfDay(for: $0.date) }.sorted(by: >)
                if let mostRecent = sortedDates.first,
                   let yesterday = calendar.date(byAdding: .day, value: -1, to: today),
                   mostRecent >= yesterday {
                    var streak = 1
                    var currentDate = mostRecent
                    for date in sortedDates.dropFirst() {
                        guard let expected = calendar.date(byAdding: .day, value: -1, to: currentDate) else { break }
                        if date == expected {
                            streak += 1
                            currentDate = date
                        } else if date == currentDate {
                            continue
                        } else {
                            break
                        }
                    }
                    streakDays = streak
                }
            } catch {
                #if DEBUG
                print("[Profile] Error loading history: \(error)")
                #endif
            }
        }

        if let profileRepo = resolver.resolve(UserProfileRepository.self) {
            userProfile = try? await profileRepo.loadProfile()
        }
    }

    private func loadEntitlement() async {
        #if DEBUG
        if DebugEntitlementOverride.shared.isEnabled {
            entitlement = DebugEntitlementOverride.shared.entitlement
            debugModeEnabled = true
            debugIsPro = DebugEntitlementOverride.shared.isPro
            return
        }
        #endif

        if let repo = entitlementRepository {
            do {
                entitlement = try await repo.currentEntitlement()
            } catch {
                print("Failed to load entitlement: \(error)")
            }
        }
    }

    private func restorePurchases() async {
        do {
            let info = try await Purchases.shared.restorePurchases()
            await loadEntitlement()
            let hasActive = info.entitlements.all.values.contains { $0.isActive }
            restoreMessage = hasActive
                ? "settings.restore_success".localized
                : "settings.restore_not_found".localized
        } catch {
            restoreMessage = "settings.restore_not_found".localized
        }
        showingRestoreAlert = true
    }

    private func openSupportURL() {
        if let url = URL(string: "mailto:support@fittoday.app") {
            UIApplication.shared.open(url)
        }
    }

    #if DEBUG
    private func handleDebugModeChange(_ enabled: Bool) {
        DebugEntitlementOverride.shared.isEnabled = enabled
        if enabled {
            debugIsPro = DebugEntitlementOverride.shared.isPro
            handleDebugProChange(debugIsPro)
        } else {
            Task { await loadEntitlement() }
        }
    }

    private func handleDebugProChange(_ isPro: Bool) {
        DebugEntitlementOverride.shared.isPro = isPro
        entitlement = DebugEntitlementOverride.shared.entitlement
    }
    #endif
}

#Preview {
    NavigationStack {
        ProfileProView()
            .environment(\.dependencyResolver, Container())
            .environment(AppRouter())
    }
}

